INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('clinical_guideline', 'diabetes_type2', ARRAY['ذیابیطس','ٹائپ 2','میٹفارمین','شوگر کنٹرول'], 'ٹائپ 2 ذیابیطس کا انتظام', E'## ٹائپ 2 ذیابیطس کا انتظام\n\n**تشخیص:** فاسٹنگ شوگر ≥126 یا HbA1c ≥6.5%\n\n**مرحلہ 1:** طرز زندگی + میٹفارمین 500mg دو بار\n**مرحلہ 2:** سلفونیل یوریا یا DPP-4 inhibitor شامل کریں\n**مرحلہ 3:** بیسل انسولین شامل کریں\n\n**اہداف:**\n- HbA1c < 7%\n- فاسٹنگ شوگر 80-130\n- BP < 130/80\n\n**باقاعدہ جانچ:** HbA1c ہر 3 ماہ، پاؤں سالانہ، آنکھیں سالانہ، گردے سالانہ', 'ur', 'ADA/WHO', 6, true),
('clinical_guideline', 'hypertension', ARRAY['ہائی بلڈ پریشر','BP','املوڈیپین','لوسارٹن'], 'ہائی بلڈ پریشر کا علاج', E'## ہائی بلڈ پریشر کا مرحلہ وار علاج\n\n**تشخیص:** دو الگ مواقع پر ≥140/90\n\n**مرحلہ 1:** ACE inhibitor یا ARB\n**مرحلہ 2:** کیلشیم چینل بلاکر شامل کریں\n**مرحلہ 3:** تھائزائیڈ شامل کریں\n**مرحلہ 4:** سپائرونولیکٹون شامل کریں\n\n**ہدف:** < 140/90 (ذیابیطس: < 130/80)\n\n**ہنگامی:** BP > 180/120 + علامات → فوری ہسپتال', 'ur', 'NICE/JNC', 6, true),
('clinical_guideline', 'asthma_action', ARRAY['دمہ','بخاخ','سالبوٹامول','علاج'], 'دمہ کا ایکشن پلان', E'## دمہ کا ایکشن پلان\n\n**مرحلہ 1:** سالبوٹامول ضرورت پر\n**مرحلہ 2:** کم خوراک ICS شامل کریں\n**مرحلہ 3:** LABA شامل کریں یا ICS بڑھائیں\n**مرحلہ 4:** درمیانی ICS + LABA\n**مرحلہ 5:** ماہر کو حوالہ\n\n**شدید حملہ:**\n- سالبوٹامول 4-10 پف ہر 20 منٹ\n- پریڈنیزولون 40-50mg × 5 دن\n- آکسیجن SpO2 > 94% رکھیں\n\n**فوری حوالہ:** بہتری نہیں، بولنے میں مشکل، SpO2 < 92%', 'ur', 'BTS/GINA', 6, true),
('clinical_guideline', 'copd_management', ARRAY['COPD','پھیپھڑوں کی بیماری','سانس تکلیف','تمباکو'], 'COPD کا انتظام', E'## COPD کا انتظام\n\n**تشخیص:** FEV1/FVC < 0.7 موسع قصبی کے بعد\n\n**علاج:**\n- گروپ A: SABA ضرورت پر\n- گروپ B: LABA یا LAMA\n- گروپ E: LABA + LAMA ± ICS\n\n**بنیادی اقدامات:**\n- تمباکو چھوڑنا (سب سے اہم)\n- انفلوئنزا + نمونیا ویکسین\n- پلمونری بحالی\n\n**شدید حملہ:** پریڈنیزولون 30-40mg × 5 دن + اینٹی بائیوٹک اگر بلغم پیلا/سبز', 'ur', 'GOLD/NICE', 6, true),
('clinical_guideline', 'pregnancy_care', ARRAY['حمل','حاملہ','فولک ایسڈ','زچگی'], 'حمل کی دیکھ بھال', E'## حمل کی دیکھ بھال\n\n**پہلی سہ ماہی:**\n- فولک ایسڈ 400mcg روزانہ\n- ٹیسٹ: بلڈ گروپ، CBC، شوگر، پیشاب، HIV، HBsAg\n- 12 ہفتے پر الٹراساؤنڈ\n\n**دوسری سہ ماہی:**\n- آئرن + فولک ایسڈ روزانہ\n- 20 ہفتے: تشوہات کا معائنہ\n- 24-28 ہفتے: حمل کی شوگر ٹیسٹ\n\n**تیسری سہ ماہی:**\n- BP اور پیشاب زلالیت کی نگرانی\n- بچے کی پوزیشن\n\n**خطرے کی علامات:** اندام نہانی سے خون، شدید سر درد، اچانک سوجن، بچے کی حرکت کم', 'ur', 'WHO/NICE', 6, true),
('clinical_guideline', 'anemia_workup', ARRAY['خون کی کمی','ہیموگلوبن','آئرن','فقر الدم'], 'خون کی کمی کی جانچ اور علاج', E'## خون کی کمی\n\n**تشخیص:** Hb < 13 مرد، < 12 عورتیں\n\n**ٹیسٹ:**\n1. CBC + خون کی فلم\n2. آئرن، فیریٹین، TIBC\n3. B12 اور فولک ایسڈ\n4. گردے اور جگر فنکشن\n\n**علاج:**\n- آئرن کی کمی: فیرس سلفیٹ 200mg × 3 روزانہ × 3 ماہ\n- B12 کی کمی: 1000mcg انجکشن\n- فولک ایسڈ کمی: 5mg روزانہ\n\n**فوری حوالہ:** Hb < 7 یا فعال خون بہنا یا دل کی علامات', 'ur', 'WHO/BSH', 6, true),
('clinical_guideline', 'thyroid_disorders', ARRAY['تھائرائڈ','غدود','TSH','ہارمون'], 'تھائرائڈ کے مسائل', E'## تھائرائڈ کے مسائل\n\n**کم تھائرائڈ:**\n- علامات: تھکاوٹ، وزن بڑھنا، قبض، خشک جلد\n- تشخیص: TSH زیادہ، T4 کم\n- علاج: لیوو تھائروکسین 25-50mcg شروع\n\n**زیادہ تھائرائڈ:**\n- علامات: دھڑکن، وزن کم، کانپنا، پسینہ\n- تشخیص: TSH کم، T4/T3 زیادہ\n- علاج: کاربیمازول + بیٹا بلاکر\n\n**فالو اپ:** TSH ہر 6-8 ہفتے جب تک مستحکم، پھر ہر 6 ماہ', 'ur', 'ATA/NICE', 6, true),
('clinical_guideline', 'depression_screening', ARRAY['ڈپریشن','PHQ-9','ذہنی صحت','اداسی'], 'ڈپریشن کی جانچ اور علاج', E'## ڈپریشن (PHQ-9)\n\n**درجہ بندی:**\n- 5-9: ہلکا → نگرانی\n- 10-14: درمیانا → نفسیاتی علاج ± دوا\n- 15-19: شدید → SSRI + نفسیاتی علاج\n- ≥20: بہت شدید → فوری حوالہ\n\n**دوائی علاج:**\n- پہلی لائن: فلوکسیٹین 20mg یا سرٹرالین 50mg\n- 4-6 ہفتے بعد جائزہ\n- بہتری کے بعد 6 ماہ جاری رکھیں\n\n**⚠️ فوری حوالہ:** خودکشی کے خیالات یا خود کو نقصان', 'ur', 'NICE/WHO', 6, true),
('clinical_guideline', 'pediatric_diarrhea', ARRAY['بچوں میں اسہال','پانی کی کمی','ORS','زنک'], 'بچوں میں اسہال اور پانی کی کمی', E'## بچوں میں اسہال\n\n**پانی کی کمی کا اندازہ:**\n- نہیں: پلان A - ہر اسہال بعد ORS\n- درمیانی: پلان B - 75mL/kg ORS 4 گھنٹے میں\n- شدید: پلان C - فوری IV سیلائن\n\n**علاج:**\n1. ORS پانی کی کمی کے مطابق\n2. زنک 20mg/دن × 10-14 دن (6 ماہ سے کم: 10mg)\n3. دودھ اور کھانا جاری رکھیں\n4. اینٹی بائیوٹک صرف خونی اسہال میں\n\n**فوری حوالہ:** شدید پانی کی کمی، خون، 3 ماہ سے کم عمر + بخار', 'ur', 'WHO/IMCI', 6, true),
('clinical_guideline', 'malaria_treatment', ARRAY['ملیریا','بخار','مچھر','آرٹیمیسینین'], 'ملیریا کا علاج', E'## ملیریا کا علاج\n\n**تشخیص:** خون کی سلائیڈ یا RDT\n\n**P. falciparum:**\n- ACT: آرٹیمیتھر-لومیفینٹرین × 3 دن\n\n**P. vivax:**\n- کلوروکوین × 3 دن + پرائماکوین 14 دن\n- G6PD ٹیسٹ پرائماکوین سے پہلے\n\n**شدید ملیریا:**\n- آرٹیسونیٹ IV + ہسپتال منتقلی\n\n**بچاؤ:** مچھر دانی، کیڑا مار سپرے', 'ur', 'WHO', 6, true),
('clinical_guideline', 'tb_screening', ARRAY['ٹی بی','سل','کھانسی','وزن کم'], 'ٹی بی کی جانچ اور علاج', E'## ٹی بی (Tuberculosis)\n\n**شبہ:** 2 ہفتے سے زیادہ کھانسی، رات کا پسینہ، بخار، وزن کم\n\n**ٹیسٹ:**\n1. سینے کا ایکسرے\n2. بلغم × 3 (رنگائی اور کلچر)\n3. GeneXpert اگر دستیاب\n\n**علاج:**\n- شدید مرحلہ (2 ماہ): HRZE\n- جاری مرحلہ (4 ماہ): HR\n- DOT (براہ راست نگرانی میں علاج)\n\n**فالو اپ:** بلغم ٹیسٹ ماہ 2، 5، 6\n\n**حوالہ:** دوا مزاحمت، پھیپھڑوں سے باہر ٹی بی', 'ur', 'WHO/NTCP', 6, true),
('clinical_guideline', 'hiv_pep', ARRAY['HIV','PEP','بچاؤ','سوئی چبھنا'], 'HIV سے بچاؤ (PEP)', E'## PEP - تعرض کے بعد بچاؤ\n\n**شروع:** 72 گھنٹے کے اندر (بہتر 2 گھنٹے میں)\n\n**ادویات:**\n- TDF + 3TC (یا FTC) + Dolutegravir\n- مدت: 28 دن\n\n**ٹیسٹ:**\n- شروع سے پہلے HIV ٹیسٹ (منفی ہونا ضروری)\n- گردے اور جگر فنکشن\n- فالو اپ: HIV ٹیسٹ 6 ہفتے، 3 ماہ، 6 ماہ\n\n**تعرض کی صورتیں:** سوئی چبھنا، جنسی تعرض، آلودہ خون سے رابطہ', 'ur', 'WHO', 6, true),
('clinical_guideline', 'wound_care', ARRAY['زخم','ٹانکے','صفائی','ٹیٹنس'], 'زخم کی دیکھ بھال', E'## زخم کی دیکھ بھال\n\n**صفائی:**\n1. نمکین پانی یا صاف پانی سے دھوئیں\n2. غیر ملکی اجسام نکالیں\n3. بیٹاڈین سے صاف کریں\n\n**ٹانکے:** 6 گھنٹے کے اندر (چہرہ 24 گھنٹے تک)\n\n**اینٹی بائیوٹک:** آلودہ زخم یا کاٹنے میں\n- اموکسیسیلین/کلاویولینٹ 625mg × 3\n\n**ٹیٹنس:**\n- صاف زخم + مکمل ٹیکے: ضرورت نہیں\n- آلودہ زخم: بوسٹر + امیونوگلوبولین اگر ٹیکے نامکمل\n\n**فالو اپ:** ٹانکے 7-10 دن بعد نکالیں (چہرہ 5 دن)', 'ur', 'WHO', 6, true),
('clinical_guideline', 'burns_management', ARRAY['جلنا','آگ','گرم پانی','جلد'], 'جلنے کا علاج', E'## جلنے کا علاج\n\n**درجہ بندی:**\n- پہلا: سرخی\n- دوسرا: چھالے\n- تیسرا: سفید/جلا ہوا\n\n**ابتدائی طبی امداد:**\n1. 20 منٹ ٹھنڈا بہتا پانی\n2. زیورات اور غیر چپکے کپڑے اتاریں\n3. صاف پٹی لگائیں\n\n**رقبہ:** نو کا اصول یا مریض کی ہتھیلی = 1%\n\n**ہسپتال منتقلی:**\n- رقبہ > 10% بالغ یا > 5% بچہ\n- چہرہ، ہاتھ، جننی علاقہ\n- بجلی یا کیمیائی جلنا\n\n**سیال:** پارکلینڈ: 4mL × kg × % رقبہ', 'ur', 'WHO/ABA', 6, true),
('clinical_guideline', 'fracture_first_aid', ARRAY['ہڈی ٹوٹنا','کسر','سپلنٹ','چوٹ'], 'ہڈی ٹوٹنے کی ابتدائی مدد', E'## ہڈی ٹوٹنے کی ابتدائی مدد\n\n**علامات:** شدید درد، سوجن، ٹیڑھا پن، حرکت میں مشکل\n\n**ابتدائی مدد:**\n1. عارضی سپلنٹ سے جوڑ باندھیں\n2. برف (20 منٹ ہر گھنٹے)\n3. حصہ اوپر رکھیں\n4. درد: پیراسیٹامول یا ٹرامادول\n\n**⚠️ کھلا فریکچر:**\n- صاف پٹی لگائیں\n- ہڈی واپس ڈالنے کی کوشش نہ کریں\n- اینٹی بائیوٹک + ٹیٹنس\n- فوری سرجیکل حوالہ\n\n**فوری حوالہ:** نبض غائب، سن ہونا، کھلا فریکچر، کولہے/ران', 'ur', 'ATLS/WHO', 6, true),
('clinical_guideline', 'uti_management', ARRAY['پیشاب انفیکشن','جلن','UTI','مثانہ'], 'پیشاب کے انفیکشن کا علاج', E'## پیشاب کے انفیکشن\n\n**نچلا (مثانہ):**\n- علامات: جلن، بار بار پیشاب\n- علاج: نائٹروفیورنٹوئن 100mg × 2 × 5 دن\n\n**اوپری (گردے):**\n- علامات: بخار، کمر درد، متلی\n- علاج: سیپروفلوکساسین 500mg × 2 × 7 دن\n\n**حمل میں:** نائٹروفیورنٹوئن یا سیفالیکسین\n\n**حوالہ:** بار بار انفیکشن، مردوں میں UTI، خون + بخار', 'ur', 'NICE/EAU', 6, true),
('clinical_guideline', 'childhood_vaccination', ARRAY['ٹیکے','بچوں کے ٹیکے','EPI','حفاظتی ٹیکے'], 'بچوں کے حفاظتی ٹیکے', E'## EPI - بچوں کے حفاظتی ٹیکے\n\n**پیدائش:** BCG + OPV-0 + Hep B\n**6 ہفتے:** Penta-1 + OPV-1 + PCV-1 + Rota-1\n**10 ہفتے:** Penta-2 + OPV-2 + Rota-2\n**14 ہفتے:** Penta-3 + OPV-3 + PCV-2 + IPV\n**9 ماہ:** خسرہ-1 + PCV-3\n**15 ماہ:** خسرہ-2\n\n**اہم:**\n- ہلکا بخار ٹیکے کی وجہ سے نارمل ہے\n- پیراسیٹامول دے سکتے ہیں\n- شدید الرجی کی صورت میں اگلی خوراک نہ دیں', 'ur', 'WHO/EPI', 6, true),
('clinical_guideline', 'acute_gastroenteritis', ARRAY['معدے آنتوں کی سوزش','اسہال الٹی','فوڈ پوائزننگ'], 'معدے آنتوں کی سوزش', E'## شدید معدے آنتوں کی سوزش\n\n**علاج:**\n1. ORS - پانی کی کمی پوری کریں\n2. BRAT غذا: کیلا، چاول، سیب، ٹوسٹ\n3. زنک (بچوں میں)\n4. اینٹی بائیوٹک: صرف خونی اسہال یا سفری اسہال میں\n\n**جب اینٹی بائیوٹک:**\n- Ciprofloxacin 500mg × 2 × 3 دن (بالغ)\n- شدید Shigella/Salmonella\n\n**حوالہ:** شدید پانی کی کمی، 48 گھنٹے سے زیادہ، خونی اسہال', 'ur', 'WHO/NICE', 6, true),
('clinical_guideline', 'iron_deficiency', ARRAY['آئرن کی کمی','فیریٹین','خون کی کمی عورتوں میں'], 'آئرن کی کمی کا انتظام', E'## آئرن کی کمی\n\n**تشخیص:** فیریٹین < 30, کم MCV, کم MCH\n\n**وجوہات تلاش کریں:**\n- ماہواری زیادہ\n- معدے سے خون (السر، کینسر)\n- غذائی کمی\n- حمل\n\n**علاج:**\n- فیرس سلفیٹ 200mg × 2-3 روزانہ\n- وٹامن C ساتھ (جذب بہتر)\n- 3 ماہ بعد Hb اور فیریٹین چیک\n\n**حوالہ:** مردوں میں یا بعد از سن یاس خواتین میں → معدے/آنتوں کی جانچ ضروری', 'ur', 'BSH/NICE', 6, true),
('clinical_guideline', 'snake_bite', ARRAY['سانپ کا کاٹنا','زہر','اینٹی وینم'], 'سانپ کے کاٹنے کا علاج', E'## سانپ کے کاٹنے کا علاج\n\n**ابتدائی مدد:**\n1. مریض کو آرام دیں\n2. متاثرہ حصہ حرکت نہ دیں\n3. زیورات اتاریں\n4. ہسپتال فوری منتقل کریں\n\n**نہ کریں:** چوسنا، کاٹنا، ٹورنیکیٹ\n\n**اینٹی وینم کی ضرورت:**\n- سوجن بڑھ رہی ہے\n- خون بہنے کی علامات\n- اعصابی علامات (پلکیں جھکنا)\n- پیشاب سیاہ\n\n**نگرانی:** 24 گھنٹے ہسپتال میں، خون جمنے کے ٹیسٹ ہر 6 گھنٹے', 'ur', 'WHO', 6, true),
('clinical_guideline', 'heat_stroke', ARRAY['لو لگنا','گرمی','درجہ حرارت بڑھنا','دھوپ'], 'لو لگنا (Heat Stroke)', E'## لو لگنا\n\n**شناخت:** جسمانی درجہ حرارت > 40°C + شعور میں تبدیلی\n\n**فوری اقدامات:**\n1. سائے میں لے جائیں\n2. کپڑے ڈھیلے/اتاریں\n3. ٹھنڈا پانی جسم پر ڈالیں\n4. پنکھا/ایئر کنڈیشنر\n5. برف بغلوں اور گردن پر\n6. IV سیلائن\n\n**⚠️ ہنگامی:** درجہ حرارت > 41°C + بے ہوشی + دورے → ICU فوری\n\n**بچاؤ:** پانی زیادہ پیئیں، دھوپ سے بچیں، ہلکے کپڑے', 'ur', 'WHO', 6, true);
INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('clinical_guideline', 'pneumonia_treatment', ARRAY['نمونیا','پھیپھڑوں کی سوزش','بخار','کھانسی'], 'نمونیا کا علاج', E'## نمونیا کا علاج\n\n**شدت کا اندازہ (CURB-65):**\n- Confusion، Urea > 7، RR ≥ 30، BP < 90/60، عمر ≥ 65\n- 0-1: گھر پر علاج\n- 2: ہسپتال غور کریں\n- 3+: ہسپتال داخل\n\n**گھر پر:** اموکسیسیلین 500mg × 3 × 5 دن\n**ہسپتال:** اموکسیسیلین IV + کلیریتھرومائسین\n\n**⚠️ حوالہ:** SpO2 < 92%، bilateral، immunocompromised', 'ur', 'BTS/NICE', 6, true),
('clinical_guideline', 'diabetes_foot_care', ARRAY['ذیابیطس پاؤں','پاؤں کا زخم','اعصابی نقصان'], 'ذیابیطس میں پاؤں کی دیکھ بھال', E'## ذیابیطس - پاؤں کی دیکھ بھال\n\n**سالانہ جانچ:**\n- احساس (monofilament)\n- نبض (dorsalis pedis, posterior tibial)\n- جلد کی حالت\n- ناخن\n\n**مریض کی ہدایات:**\n- روزانہ پاؤں دیکھیں\n- نرم جوتے پہنیں\n- ننگے پاؤں نہ چلیں\n- ناخن سیدھے کاٹیں\n\n**⚠️ فوری حوالہ:**\n- زخم جو ٹھیک نہ ہو\n- سوجن + سرخی + بخار (انفیکشن)\n- سیاہ حصہ (gangrene)', 'ur', 'ADA/NICE', 6, true),
('clinical_guideline', 'epilepsy_management', ARRAY['مرگی','دورے','فٹس','اینٹی ایپیلیپٹک'], 'مرگی کا انتظام', E'## مرگی کا انتظام\n\n**تشخیص:** 2 یا زیادہ بلا اشتعال دورے\n\n**ادویات:**\n- Focal: Carbamazepine یا Lamotrigine\n- Generalized: Sodium Valproate (عورتوں میں محتاط)\n- عورتوں میں: Lamotrigine یا Levetiracetam\n\n**اہم ہدایات:**\n- دوا باقاعدگی سے لیں\n- اچانک بند نہ کریں\n- ڈرائیونگ: 12 ماہ بغیر دورے\n- حمل: پہلے سے منصوبہ بندی ضروری\n\n**فوری حوالہ:** 5 منٹ سے زیادہ دورے، پہلا دورہ', 'ur', 'NICE/ILAE', 6, true),
('clinical_guideline', 'gout_management', ARRAY['گاؤٹ','نقرس','یورک ایسڈ','جوڑوں کا درد'], 'گاؤٹ کا علاج', E'## گاؤٹ (نقرس)\n\n**شدید حملہ:**\n- Colchicine 500mcg × 2-3 بار\n- یا NSAID (Naproxen 500mg × 2)\n- یا Prednisolone 30mg × 5 دن\n\n**بچاؤ (6 ماہ بعد):**\n- Allopurinol 100mg شروع، آہستہ بڑھائیں\n- ہدف: یورک ایسڈ < 6 mg/dL\n- پہلے 6 ماہ colchicine cover دیں\n\n**طرز زندگی:** شراب کم، گوشت کم، پانی زیادہ\n\n**⚠️ شدید حملے میں Allopurinol شروع نہ کریں', 'ur', 'BSR/EULAR', 6, true),
('clinical_guideline', 'chronic_kidney', ARRAY['گردے کی بیماری','CKD','کریٹینین','eGFR'], 'دائمی گردے کی بیماری', E'## دائمی گردے کی بیماری (CKD)\n\n**مراحل:**\n- Stage 1-2: eGFR > 60 - نگرانی\n- Stage 3: eGFR 30-59 - فعال انتظام\n- Stage 4: eGFR 15-29 - ماہر حوالہ\n- Stage 5: eGFR < 15 - ڈائلیسس/ٹرانسپلانٹ\n\n**انتظام:**\n- BP < 130/80 (ACEi/ARB)\n- ذیابیطس کنٹرول\n- نقصان دہ دوائیں بند (NSAIDs)\n- پروٹین محدود (Stage 4-5)\n\n**باقاعدہ ٹیسٹ:** eGFR، پوٹاشیم، کیلشیم، فاسفیٹ، Hb', 'ur', 'KDIGO/NICE', 6, true),
('clinical_guideline', 'heart_failure', ARRAY['دل فیل','سانس تکلیف','ٹانگوں سوجن','دل کی کمزوری'], 'دل کی ناکامی کا علاج', E'## دل کی ناکامی\n\n**تشخیص:** BNP + ایکو کارڈیوگرام\n\n**ادویات (HFrEF):**\n1. ACEi/ARB + Beta-blocker (بنیاد)\n2. Spironolactone شامل کریں\n3. SGLT2 inhibitor شامل کریں\n4. Loop diuretic (علامات کے لیے)\n\n**مریض کی ہدایات:**\n- نمک کم\n- سیال 1.5-2L/دن\n- روزانہ وزن (1kg/دن بڑھے → ڈاکٹر)\n- ورزش مناسب\n\n**⚠️ ہنگامی:** سانس تکلیف لیٹنے پر + ٹانگیں سوجن → فوری ہسپتال', 'ur', 'ESC/NICE', 6, true);
